   |Name = wrapWidth
   |Type = float
  }}{{FunctionArgument
   |Name = resWidth
   |Type = ScriptVar
  }}{{FunctionArgument
   |Name = resHeight
   |Type = ScriptVar
  }}{{FunctionArgument
   |Name = resNumLines
   |Type = ScriptVar
  }}
